    hpfEnabledAttachment=std::make_unique<juce::AudioProcessorValueTreeState::ButtonAttachment>(p.state,"hpfEnabled",hpfEnabled);bellEnabledAttachment=std::make_unique<juce::AudioProcessorValueTreeState::ButtonAttachment>(p.state,"bellEnabled",bellEnabled);lpfEnabledAttachment=std::make_unique<juce::AudioProcessorValueTreeState::ButtonAttachment>(p.state,"lpfEnabled",lpfEnabled);hpfSlopeAttachment=std::make_unique<juce::AudioProcessorValueTreeState::ComboBoxAttachment>(p.state,"hpfSlope",hpfSlope);lpfSlopeAttachment=std::make_unique<juce::AudioProcessorValueTreeState::ComboBoxAttachment>(p.state,"lpfSlope",lpfSlope);
