    savePreset.onClick=[this,presetFolder]{auto chooser=std::make_shared<juce::FileChooser>("Salva preset",presetFolder.getChildFile("Comparison.rlpreset"),"*.rlpreset");chooser->launchAsync(juce::FileBrowserComponent::saveMode|juce::FileBrowserComponent::canSelectFiles|juce::FileBrowserComponent::warnAboutOverwriting,[this,chooser](const juce::FileChooser&f){if(f.getResult()!=juce::File{}){juce::String error;if(!p.saveComparisonPreset(f.getResult().withFileExtension("rlpreset"),error))showError(error);}});};
    loadPreset.onClick=[this,presetFolder]{auto chooser=std::make_shared<juce::FileChooser>("Carica preset",presetFolder,"*.rlpreset");chooser->launchAsync(juce::FileBrowserComponent::openMode|juce::FileBrowserComponent::canSelectFiles,[this,chooser](const juce::FileChooser&f){if(f.getResult().existsAsFile()){juce::String error;if(!p.loadComparisonPreset(f.getResult(),error))showError(error);}});};
