void ReferenceLabEditor::refreshLibrary(){referencelab::ReferenceFilter f;f.query=search.getText();f.favouritesOnly=favouritesOnly.getToggleState();f.sort=static_cast<referencelab::ReferenceSort>(juce::jmax(0,sort.getSelectedId()-1));rows=p.getReferenceManager().filter(f);list.updateContent();list.repaint();}
void ReferenceLabEditor::showError(const juce::String&e){juce::NativeMessageBox::showMessageBoxAsync(juce::MessageBoxIconType::WarningIcon,"ReferenceLab",e);}
void ReferenceLabEditor::chooseFolder(){auto chooser=std::make_shared<juce::FileChooser>("Cartella reference");chooser->launchAsync(juce::FileBrowserComponent::openMode|juce::FileBrowserComponent::canSelectDirectories,[this,chooser](const juce::FileChooser&f){if(f.getResult().isDirectory()){juce::String warning;p.getReferenceManager().scanFolder(f.getResult(),true,warning);if(warning.isNotEmpty())showError(warning);refreshLibrary();}});}
void ReferenceLabEditor::paintListBoxItem(int row,juce::Graphics&g,int w,int h,bool selected){if(row<0||row>=getNumRows())return;if(selected)g.fillAll(juce::Colour(0xff315b78));auto lib=p.getReferenceManager().snapshot();auto file=rows[(size_t)row].resolveAgainst(lib.root);auto state=p.getCacheManager().getState(file);juce::String badge=state==referencelab::CacheState::cached?"[CACHE] ":state==referencelab::CacheState::loading?"[LOAD] ":state==referencelab::CacheState::error?"[ERR] ":"";g.setColour(file.existsAsFile()?juce::Colours::white:juce::Colours::orangered);g.drawText(badge+rows[(size_t)row].title+"  -  "+rows[(size_t)row].artist,10,0,w-20,h,juce::Justification::centredLeft,true);}
void ReferenceLabEditor::listBoxItemDoubleClicked(int row,const juce::MouseEvent&){if(row<0||row>=getNumRows())return;configurePlayback(row);auto file=rows[(size_t)row].resolveAgainst(p.getReferenceManager().snapshot().root);juce::Component::SafePointer<ReferenceLabEditor>safe(this);p.loadFileAsync(file,[safe](const juce::String&error){if(!safe)return;if(error.isNotEmpty())safe->showError(error);else safe->p.setReference(true);safe->list.repaint();});list.repaint();}
void ReferenceLabEditor::selectedRowsChanged(int row){if(row<0||row>=getNumRows())return;auto&m=rows[(size_t)row];editTitle.setText(m.title,false);editArtist.setText(m.artist,false);editGenre.setText(m.genre,false);editBpm.setText(m.bpm?juce::String(*m.bpm,2):juce::String{},false);editTags.setText(m.tags.joinIntoString(", "),false);editFavourite.setToggleState(m.favourite,juce::dontSendNotification);auto duration=juce::jmax(1.0,m.durationSeconds);for(auto*s:{&seek,&startOffset,&loopStart,&loopEnd})s->setRange(0.0,duration,.01);startOffset.setValue(m.startOffsetSeconds,juce::dontSendNotification);loopStart.setValue(m.loop.startSeconds,juce::dontSendNotification);loopEnd.setValue(m.loop.endSeconds,juce::dontSendNotification);loopEnabled.setToggleState(m.loop.enabled,juce::dontSendNotification);}
void ReferenceLabEditor::configurePlayback(int row){if(row<0||row>=getNumRows())return;auto&m=rows[(size_t)row];p.getPlayer().setStartOffset(m.startOffsetSeconds);p.getPlayer().setLoop(m.loop.enabled,m.loop.startSeconds,m.loop.endSeconds,m.loop.crossfadeMs);}
void ReferenceLabEditor::applyLoop(){p.getPlayer().setLoop(loopEnabled.getToggleState(),loopStart.getValue(),loopEnd.getValue());}
void ReferenceLabEditor::persistPlayback(){auto row=list.getSelectedRow();if(row<0||row>=getNumRows())return;auto item=rows[(size_t)row];item.startOffsetSeconds=startOffset.getValue();item.loop.enabled=loopEnabled.getToggleState();item.loop.startSeconds=loopStart.getValue();item.loop.endSeconds=loopEnd.getValue();if(item.loop.enabled&&!item.loop.isValid()){showError("Il marker B deve essere successivo al marker A");return;}juce::String error;if(!p.getReferenceManager().updateMetadata(item,error))showError(error);else rows[(size_t)row]=std::move(item);}
void ReferenceLabEditor::saveSelected(){auto row=list.getSelectedRow();if(row<0||row>=getNumRows())return;auto item=rows[(size_t)row];item.title=editTitle.getText().trim();item.artist=editArtist.getText().trim();item.genre=editGenre.getText().trim();item.favourite=editFavourite.getToggleState();item.tags=juce::StringArray::fromTokens(editTags.getText(),",","\"");item.tags.trim();item.tags.removeEmptyStrings();auto bpm=editBpm.getText().trim();item.bpm=bpm.isEmpty()?std::nullopt:std::optional<double>(bpm.getDoubleValue());juce::String error;if(!p.getReferenceManager().updateMetadata(item,error))showError(error);refreshLibrary();}
void ReferenceLabEditor::removeSelected(){auto row=list.getSelectedRow();if(row<0||row>=getNumRows())return;juce::String error;if(!p.getReferenceManager().remove(rows[(size_t)row].uuid,error))showError(error);refreshLibrary();}
void ReferenceLabEditor::timerCallback(){auto text=[](const char*name,const referencelab::MeterSnapshot&m){return juce::String(name)+"  LUFS "+juce::String(m.shortTermLufs,1)+"  Peak "+juce::String(m.peakDb,1)+"  TP "+juce::String(m.truePeakDbtp,1)+"  RMS "+juce::String(m.rmsDb,1)+"  Crest "+juce::String(m.crestDb,1)+"  DR "+juce::String(m.dynamicRangeDb,1);};mixMeters.setText(text("MIX",p.getMixMeters()),juce::dontSendNotification);referenceMeters.setText(text("REF",p.getReferenceMeters()),juce::dontSendNotification);auto o=p.getOutputMeters();outputMeters.setText("OUT  Corr "+juce::String(o.correlation,2)+"  Width "+juce::String(o.stereoWidth,2),juce::dontSendNotification);matchedGain.setText("Applied "+juce::String(p.getMatchedGainDb(),1)+" dB",juce::dontSendNotification);transportStatus.setText(transportSync.getToggleState()?(p.isTransportAvailable()?"DAW OK":"DAW N/A"):"FREE",juce::dontSendNotification);if(!seek.isMouseButtonDown())seek.setValue(p.getPlayer().getPositionSeconds(),juce::dontSendNotification);list.repaint();}
void ReferenceLabEditor::paint(juce::Graphics&g){g.fillAll(juce::Colour(0xff10151d));g.setColour(juce::Colour(0xff263241));g.fillRoundedRectangle(getLocalBounds().reduced(16).toFloat(),10);}
bool ReferenceLabEditor::keyPressed(const juce::KeyPress&key){if(key.getTextCharacter()=='b'||key.getTextCharacter()=='B'){p.setReference(!p.isReference());return true;}if(key==juce::KeyPress::spaceKey){p.getPlayer().isPlaying()?p.pauseReference():p.playReference();return true;}return false;}
